def addition(a, b):
    # On additionne simplement les deux nombres reçus en paramètre
    return a + b

def nombre_de_lettres(mot):
    # len() renvoie le nombre de caractères d'une chaîne
    return len(mot)

def premiere_lettre(mot):
    # L'indice 0 correspond toujours au premier caractère d'une chaîne
    return mot[0]

def repetition(lettre, n):
    # La multiplication d'une chaîne par un entier la répète ce nombre de fois
    return n * lettre

def concatenation(mot1, mot2):
    # + concatène deux chaînes de caractères bout à bout
    return mot1 + mot2

def mot_a_trou(mot, lettre):
    resultat = ""
    # On parcourt le mot lettre par lettre
    for l in mot:
        if l != lettre:
            resultat += l
        else:
            # On remplace la lettre recherchée par un underscore
            resultat += "_"
    return resultat

def consonnes(mot):
    voyelles = "aeiouy"
    resultat = ""
    for lettre in mot:
        # On ne garde que les lettres qui ne sont PAS des voyelles
        if lettre not in voyelles:
            resultat += lettre
    return resultat

def contient_mot(phrase, mot):
    n_m = len(mot)
    n_p = len(phrase)
    # On teste toutes les positions de départ possibles dans phrase : la
    # dernière position valide est n_p - n_m (+1 car range s'arrête avant
    # sa borne haute)
    for i in range(n_p - n_m + 1):
        if phrase[i:i+n_m] == mot:
            return True
    return False

def majeur(age):
    # True si age est supérieur ou égal à 18, False sinon
    return age >= 18

def est_pair(n):
    # Un nombre est pair si le reste de sa division par 2 vaut 0
    return n % 2 == 0

def reduction(age):
    # Loi de De Morgan : not (A or B) équivaut à (not A) and (not B)
    # Le contraire de "age < 18 ou age >= 60" est donc "age >= 18 et age < 60",
    # que l'on peut écrire en une seule comparaison : 18 <= age < 60
    # Il ne reste plus qu'à inverser ce résultat avec not
    return not (18 <= age < 60)

def somme_pairs(n):
    somme = 0
    # range(0, n, 2) parcourt 0, 2, 4, ... en s'arrêtant avant n
    for i in range(0, n, 2):
        somme += i
    return somme

def pgcd(a, b):
    if a == 0:
        return b
    if b == 0:
        return a

    # Tant que a et b sont différents, on soustrait le plus petit au plus
    # grand : le PGCD reste inchangé à chaque étape, et a finit par
    # rejoindre b (ou l'inverse)
    while a != b:
        if a > b:
            a = a - b
        else:
            b = b - a
    return a

def est_premier(n):
    # Par définition, aucun nombre inférieur à 2 n'est premier
    if n < 2:
        return False

    # On teste tous les diviseurs possibles de 2 à n-1 : si l'un d'eux
    # divise n exactement, n n'est pas premier
    for diviseur in range(2, n):
        if n % diviseur == 0:
            return False

    return True

def nombre_diviseurs(n):
    compteur = 0

    # On teste chaque nombre de 1 à n : s'il divise n sans reste, c'est
    # un diviseur
    for diviseur in range(1, n + 1):
        if n % diviseur == 0:
            compteur += 1

    return compteur

def est_palindrome(mot):
    n = len(mot)

    # On compare le caractère d'indice i (depuis le début) à celui
    # d'indice -1-i (depuis la fin) ; n//2 suffit car au-delà on
    # recomparerait les mêmes paires en sens inverse
    for i in range(n // 2):
        if mot[i] != mot[-1 - i]:
            return False

    return True

def minimum(liste):
    # On part du premier élément comme "meilleur candidat" pour le minimum
    mini = liste[0]
    # Puis on compare chaque élément suivant : si on trouve plus petit,
    # on met à jour mini
    for i in range(1, len(liste)):
        if liste[i] < mini:
            mini = liste[i]
    return mini

def indice_minimum(liste):
    # On mémorise l'INDICE du plus petit élément trouvé jusqu'ici, pas sa valeur
    imini = 0
    for i in range(1, len(liste)):
        # On compare à liste[imini] (la valeur du minimum actuel),
        # pas à une variable "mini" séparée
        if liste[i] < liste[imini]:
            imini = i
    return imini

def indices_zeros(liste):
    indices = []
    for i in range(len(liste)):
        # On vérifie la VALEUR à l'indice i avant de décider de l'ajouter
        if liste[i] == 0:
            indices.append(i)  # on stocke l'indice i, pas la valeur liste[i]
    return indices

def elements_negatifs(liste):
    negatifs = []
    # On parcourt directement les valeurs (pas besoin des indices ici)
    for x in liste:
        if x < 0:
            negatifs.append(x)
    return negatifs

